"use client";

import { useEffect, useRef } from "react";

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  maxLife: number;
  size: number;
  hue: number;
}

// Deterministic 2D smooth-ish noise via hashed gradients.
// Cheap, allocation-free, good enough for a background flow field.
function hash(x: number, y: number): number {
  const s = Math.sin(x * 127.1 + y * 311.7) * 43758.5453123;
  return s - Math.floor(s);
}
function smooth(t: number): number {
  return t * t * (3 - 2 * t);
}
function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}
function noise(x: number, y: number): number {
  const ix = Math.floor(x);
  const iy = Math.floor(y);
  const fx = x - ix;
  const fy = y - iy;
  const ux = smooth(fx);
  const uy = smooth(fy);
  const a = hash(ix, iy);
  const b = hash(ix + 1, iy);
  const c = hash(ix, iy + 1);
  const d = hash(ix + 1, iy + 1);
  return lerp(lerp(a, b, ux), lerp(c, d, ux), uy);
}
// fbm for richer turbulence
function fbm(x: number, y: number): number {
  let v = 0;
  let amp = 0.5;
  let freq = 1;
  for (let o = 0; o < 3; o++) {
    v += noise(x * freq, y * freq) * amp;
    freq *= 2;
    amp *= 0.5;
  }
  return v;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let particles: Particle[] = [];
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    // Fade overlay so particles leave trails instead of clearing each frame.
    // Lower alpha => longer trails. Tuned for elegance, not smear.
    const FADE_ALPHA = 0.06;

    const targetCount = () => {
      // Density scales with viewport area but is capped for performance.
      const area = width * height;
      const base = Math.floor(area / 5200);
      return Math.max(240, Math.min(base, 1400));
    };

    const spawn = (p: Particle, initial: boolean) => {
      if (initial) {
        p.x = Math.random() * width;
        p.y = Math.random() * height;
      } else {
        // Respawn from a random edge to keep flow continuous
        const edge = Math.floor(Math.random() * 4);
        if (edge === 0) {
          p.x = Math.random() * width;
          p.y = -4;
        } else if (edge === 1) {
          p.x = width + 4;
          p.y = Math.random() * height;
        } else if (edge === 2) {
          p.x = Math.random() * width;
          p.y = height + 4;
        } else {
          p.x = -4;
          p.y = Math.random() * height;
        }
      }
      p.vx = 0;
      p.vy = 0;
      p.maxLife = 220 + Math.random() * 360;
      p.life = initial ? Math.random() * p.maxLife : 0;
      p.size = 0.4 + Math.random() * 1.1;
      // Cool near-neutral palette: silver-blue with occasional warm spark
      const warm = Math.random() < 0.06;
      p.hue = warm ? 28 + Math.random() * 12 : 200 + Math.random() * 40;
    };

    const initParticles = () => {
      const n = targetCount();
      particles = new Array(n);
      for (let i = 0; i < n; i++) {
        const p: Particle = {
          x: 0,
          y: 0,
          vx: 0,
          vy: 0,
          life: 0,
          maxLife: 0,
          size: 0,
          hue: 0,
        };
        spawn(p, true);
        particles[i] = p;
      }
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = window.innerHeight;

      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      // Reset canvas to black baseline so fade trails build on pure black
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);

      initParticles();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    let start = performance.now();

    const draw = (now: number) => {
      const t = (now - start) * 0.0001;

      // Fade previous frame to produce elegant motion trails
      ctx.fillStyle = `rgba(0, 0, 0, ${FADE_ALPHA})`;
      ctx.fillRect(0, 0, width, height);

      const scale = 0.0016; // noise spatial scale -> broad, slow flows
      const speed = 1.35; // particle advection speed
      // Slowly rotating field angle gives gentle global drift
      const drift = t * 0.6;

      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];

        // Sample fbm flow field and map to angle. Two octaves of offset
        // create layered currents that feel organic rather than gridded.
        const nx = p.x * scale;
        const ny = p.y * scale;
        const angle =
          fbm(nx + drift, ny - drift * 0.5) * Math.PI * 4 +
          fbm(nx * 2.0 - drift * 0.3, ny * 2.0 + drift * 0.2) * Math.PI * 2;

        // Ease velocity toward field direction for smooth turns
        const tvx = Math.cos(angle) * speed;
        const tvy = Math.sin(angle) * speed;
        p.vx += (tvx - p.vx) * 0.08;
        p.vy += (tvy - p.vy) * 0.08;
        p.x += p.vx;
        p.y += p.vy;
        p.life += 1;

        // Lifecycle fade: ease-in at birth, ease-out near death
        const lifeRatio = p.life / p.maxLife;
        let alpha: number;
        if (lifeRatio < 0.15) {
          alpha = lifeRatio / 0.15;
        } else if (lifeRatio > 0.8) {
          alpha = (1 - lifeRatio) / 0.2;
        } else {
          alpha = 1;
        }
        // Depth-ish sizing based on speed for subtle parallax feel
        const sp = Math.hypot(p.vx, p.vy);
        const sizeMul = 0.7 + Math.min(sp / speed, 1) * 0.6;
        const r = Math.max(0.1, p.size * sizeMul);

        // Off-screen or expired -> respawn
        if (
          p.x < -10 ||
          p.x > width + 10 ||
          p.y < -10 ||
          p.y > height + 10 ||
          p.life >= p.maxLife
        ) {
          spawn(p, false);
          continue;
        }

        // Brightness peaks mid-life; keep overall luminance low for a
        // refined background that never competes with content.
        const lum = 0.5 + alpha * 0.5;
        const sat = 18 + (p.hue < 60 ? 30 : 12);
        ctx.fillStyle = `hsla(${p.hue}, ${sat}%, ${lum * 55}%, ${alpha * 0.5})`;
        ctx.beginPath();
        ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
        ctx.fill();
      }

      animationId = requestAnimationFrame(draw);
    };

    resize();
    start = performance.now();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-0 z-0"
    />
  );
}

content.thinking:
ユーザーは現在の fbm フロー場アニメーションを変更したいと言っています。要点:

1. **画面全体にあると鬱陶しい** → 上部の小さいスペースに限定
2. **3D版メビウスリングのような動き** → メビウスの輪（Möbius strip）のトポロジーで、3D空間上をパーティクルが流動
3. **イメージ**: 水銀、流体力学、蒼炎（青い炎）、氷

これは相当高度なビジュアル要求です。メビウスリング上をパーティクルが流れる 3D アニメーションで、水銀（金属的で重厚な反射）、流体力学（流れるような連続的运动）、蒼炎（青い炎の揺らぎ）、氷（冷たい結晶質の透明感）を融合した雰囲気。

現在は Canvas2D で実装されている。3D メビウスリングとなると、素の Canvas2D でも透視投影すれば可能だが、Three.js の方がずっと綺麗。ただしプロジェクトに three.js が入っていない。パッケージを追加するべきか？

ユーザーは「もっと洗練されてすごい点群アニメーション」と前回言っていた。今回は「3D版メビウスリング」を明示。Three.js を使うのが自然だが、依存関係を増やすのは慎重にすべき。ただし Canvas2D で手書きの 3D 投影でもメビウスリングは実装可能。パーティクル数も少なくて済む（上部の小スペース）。

判断: Canvas2D で 3D メビウスリング上のパーティクル流動を実装する。依存関係を増やさず、軽量。パーティクルがメビウスのパラメータ空間 (u, v) 上を流れ、3D 座標→透視投影→描画。メビウスの輪のパラメータ表示:
```
x = (R + v * cos(u/2)) * cos(u)
y = (R + v * cos(u/2)) * sin(u)
z = v * sin(u/2)
```
where u ∈ [0, 4π) (2周して元に戻る), v ∈ [-w, w] (帯の幅)。

パーティクルが u に沿って流動し、v 方向にも微かに揺らぐことで流体感。メビウスなので u が 2π 進むと v の符号が反転する（表裏がつながる）のがポイント。

「水銀と流体力学と蒼炎と氷」のイメージ:
- 水銀: 金属的な光沢、重厚、粒が集まる反射
- 流体力学: 連続的な流れ、渦、粘性
- 蒼炎: 青い炎、揺らぎ、上昇、発光
- 氷: 冷たい、結晶、透明、青白い

色は青白〜シアン系で、金属光沢のハイライト、炎のような揺らぎ、氷のような冷たい輝き。

実装方針:
1. Canvas を上部の小スペース（例: height の 30-40%、あるいは固定 320px 程度）に配置
2. メビウスリングの 3D パラメータでパーティクル位置を計算
3. 透視投影で 2D へ
4. パーティクルは u に沿って流動（蒼炎の上昇・揺らぎ）、v に沿って微かに揺らぐ（流体）
5. z ソートで奥行き表現（遠い粒子は小さく暗く、手前は大きく明るく＝水銀のハイライト）
6. 青白いパレット＋シアン、たまに白いハイライト（氷・水銀）
7. 残像トレイルで炎・流体感

