コード長くなるが書く。

```tsx
"use client";

import { useEffect, useRef } from "react";

interface Particle {
  u: number;
  baseV: number; // -1..1
  v: number;
  speed: number;
  size0: number;
  phase: number;
  flickerSpeed: number;
}

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: false });
    if (!ctx) return;

    let animationId = 0;
    let particles: Particle[] = [];
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    // メビウスリングの形状パラメータ
    let R = 120; // 主半径
    let W = 34;  // 帯の半幅

    const COUNT = 340;

    const initParticles = () => {
      particles = new Array(COUNT);
      for (let i = 0; i < COUNT; i++) {
        particles[i] = {
          u: Math.random() * Math.PI * 4,
          baseV: Math.random() * 2 - 1,
          v: 0,
          speed: 0.006 + Math.random() * 0.007,
          size0: 0.5 + Math.random() * 1.3,
          phase: Math.random() * Math.PI * 2,
          flickerSpeed: 1.2 + Math.random() * 2.4,
        };
      }
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      // 上部の小さなスペースに抑える
      height = Math.min(Math.max(window.innerHeight * 0.4, 240), 420);

      // リングサイズをスペースに合わせてスケール
      const scale = Math.min(width, height * 2.2) / 520;
      R = 120 * scale;
      W = 34 * scale;

      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);

      initParticles();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    // メビウスの輪のパラメータ表示。
    // u は [0, 4π) で一周（2周して表裏がつながる）。
    const mobius = (u: number, v: number) => {
      const cosHalf = Math.cos(u / 2);
      const sinHalf = Math.sin(u / 2);
      const r = R + v * cosHalf;
      // 水平面内 (x, y) + 鉛直 z
      const x = r * Math.cos(u);
      const y = r * Math.sin(u);
      const z = v * sinHalf;
      return { x, y, z };
    };

    let start = performance.now();

    const draw = (now: number) => {
      const t = (now - start) * 0.001;

      // 残像フェード（source-over で黒を薄く重ねる）
      ctx.globalCompositeOperation = "source-over";
      ctx.fillStyle = "rgba(0, 0, 0, 0.14)";
      ctx.fillRect(0, 0, width, height);

      // カメラパラメータ
      const rotY = t * 0.28;            // 鉛直軸まわりのゆっくり回転
      const tilt = -0.38;               // 俯角（見下ろし）
      const cosY = Math.cos(rotY), sinY = Math.sin(rotY);
      const cosX = Math.cos(tilt), sinX = Math.sin(tilt);
      const camDist = R * 2.6;
      const fov = R * 3.2;
      const cx = width / 2;
      const cy = height * 0.56;

      // パーティクル位置計算 + 3D 変換
      type Projected = {
        sx: number; sy: number; scale: number; depth: number;
        size0: number; flicker: number; alpha: number;
      };
      const projected: Projected[] = [];

      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];
        // 流動: u に沿って進む
        p.u += p.speed;
        if (p.u > Math.PI * 4) p.u -= Math.PI * 4;

        // 流体うねり: v が u と時間でうねる
        p.v = p.baseV * W + Math.sin(p.u * 2 + p.phase + t * 1.4) * W * 0.32;

        const m = mobius(p.u, p.v);

        // 鉛直軸まわり回転 (水平面 x,y)
        const x1 = m.x * cosY - m.y * sinY;
        const y1 = m.x * sinY + m.y * cosY;
        const z1 = m.z;

        // X 軸傾斜 (y1, z1)
        const y2 = y1 * cosX - z1 * sinX;
        const z2 = y1 * sinX + z1 * cosX;

        const dist = z2 + camDist;
        if (dist <= 1) continue;
        const s = fov / dist;
        const sx = x1 * s + cx;
        // canvas の y は下向き正。見下ろしなので鉛直上方向が画面上へ。
        const sy = -y2 * s + cy;

        const depth = Math.max(0, Math.min(1, 1 - (z2 + W) / (2 * W + camDist * 0.001)));
        // 炎揺らぎ
        const flicker = 0.5 + 0.5 * Math.sin(t * p.flickerSpeed + p.phase * 3);
        const scaleNorm = s / (fov / camDist); // 1 が標準距離

        projected.push({
          sx, sy, scale: scaleNorm, depth,
          size0: p.size0,
          flicker,
          alpha: 1,
        });
      }

      // 奥から描画（depth 昇順 = 奥が先）
      projected.sort((a, b) => a.depth - b.depth);

      ctx.globalCompositeOperation = "lighter";

      for (const p of projected) {
        // depth: 0 奥 → 1 手前
        const d = p.depth;
        const hue = 215 - d * 30;            // 215(深青) → 185(シアン)
        const sat = 70 - d * 45;             // 70 → 25 (手前は白寄り)
        const light = 28 + d * 55 + p.flicker * 8; // 28 → 83 + 炎揺らぎ
        const baseR = p.size0 * p.scale * (0.7 + p.flicker * 0.5);
        const r = Math.max(0.2, baseR);
        const alpha = (0.25 + d * 0.6) * (0.6 + p.flicker * 0.4);

        ctx.fillStyle = `hsla(${hue}, ${sat}%, ${light}%, ${alpha})`;
        ctx.beginPath();
        ctx.arc(p.sx, p.sy, r, 0, Math.PI * 2);
        ctx.fill();

        // 手前の鋭いハイライト（水銀/氷の反射）
        if (d > 0.82) {
          const hlAlpha = (d - 0.82) / 0.18 * 0.7 * p.flicker;
          ctx.fillStyle = `hsla(200, 20%, 96%, ${hlAlpha})`;
          ctx.beginPath();
          ctx.arc(p.sx, p.sy, Math.max(0.15, r * 0.45), 0, Math.PI * 2);
          ctx.fill();
        }
      }

      ctx.globalCompositeOperation = "source-over";
      animationId = requestAnimationFrame(draw);
    };

    resize();
    start = performance.now();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed top-0 left-0 z-0"
    />
  );
}
```

alpha:false のコンテキストでも lighter は動く。ただし alpha:false だと背景が黒で不透明、フェードは黒を重ねるので OK。

